module register_with_enable_reset (
    input clk,
    input enable,
    input reset,
    input [15:0] data_in,
    output reg [15:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 16'b0;
        else if (enable)
            data_out <= data_in;
    end

endmodule
